clickable-parent.css:
%root%:has(a) {
	position: relative;
}
%root% a::after {
	content: "";
	position: absolute;
	inset: 0;
	z-index: 10;
}
.target %root% a::after {
	content: "";
	position: relative;
}

focus-parent.css:
/* Tokens by default. Tip: replace these with your design system's variables. */
%root% {
	--focus-width: 2px;
	--focus-color: #1a73e8;
	--focus-offset: 2px;
}
%root%:focus-within:not(:has(:focus-visible)) {
	outline: none;
	outline-offset: 0;
	box-shadow: none;
}
%root%:focus-within {
	outline: var(--focus-width) solid var(--focus-color);
	outline-offset: var(--focus-offset);
}
%root% :focus {
	outline: none !important;
	box-shadow: none !important;
}

columns.css:
%root% {
	--col-count: auto;
	--col-min-width: 250px;
	--col-rule-style: solid;
	--col-rule-width: 1px;
	--col-rule-color: var(--black);
	--col-gap: var(--grid-gap);
	--row-gap: var(--grid-gap);
}

%root% {
	display: block !important;
	columns: var(--col-count) var(--col-min-width);
	column-rule-style: var(--col-rule-style);
	column-rule-width: var(--col-rule-width);
	column-rule-color: var(--col-rule-color);
	gap: var(--col-gap);
}

%root% > * {
	break-inside: avoid;
	margin-block-end: var(--row-gap);
}
